INSERT INTO exercises (name, description, body_part, category, default_yt_url) VALUES
('Quad Sets', 'Tighten the muscle on the front of your thigh by pushing the back of your knee down into the floor/bed.', 'Knee', 'Strength', 'https://www.youtube.com/watch?v=kYxjPjP0kZE'),
('Straight Leg Raise', 'Keep your leg straight and lift it up towards the ceiling.', 'Knee', 'Strength', 'https://www.youtube.com/watch?v=B_9-5zGEzM0'),
('Short Arc Quads', 'Place a rolled towel under your knee. Straighten your knee by lifting your heel off the bed.', 'Knee', 'Strength', 'https://www.youtube.com/watch?v=5rT88i1Y184'),
('Heel Slides', 'Slide your heel towards your buttocks, bending your knee as far as comfortable.', 'Knee', 'Stretch', 'https://www.youtube.com/watch?v=132RBY0Iud4'),
('Hamstring Curl', 'Stand holding a chair. Bend your knee, bringing your heel towards your buttocks.', 'Knee', 'Strength', 'https://www.youtube.com/watch?v=FjC3L4H9vKQ'),

('Shoulder Pendulum', 'Lean forward holding a table. Let your arm hang relaxed and gently swing it in circles.', 'Shoulder', 'Stretch', 'https://www.youtube.com/watch?v=s_tA8bUqzP4'),
('Wall Walks', 'Face a wall. Use your fingers to "walk" your hand up the wall as high as you can.', 'Shoulder', 'Stretch', 'https://www.youtube.com/watch?v=3R-z1B5oPzc'),
('Shoulder Shrugs', 'Lift your shoulders up towards your ears, then slowly lower them.', 'Shoulder', 'Strength', 'https://www.youtube.com/watch?v=yYy7xGz2zKw'),
('Internal Rotation', 'Keep your elbow at your side and pull a resistance band inward across your stomach.', 'Shoulder', 'Strength', 'https://www.youtube.com/watch?v=_uK-G93fG5Y'),
('External Rotation', 'Keep your elbow at your side and pull a resistance band outward away from your body.', 'Shoulder', 'Strength', 'https://www.youtube.com/watch?v=S01Z9pA33l4'),

('Clamshell', 'Lie on your side with hips and knees bent. Keeping your heels together, lift your top knee towards the ceiling.', 'Hip', 'Strength', 'https://www.youtube.com/watch?v=RTEP1Vj3M2s'),
('Bridges', 'Lie on your back with knees bent. Tighten your buttocks and lift your hips off the floor.', 'Hip', 'Strength', 'https://www.youtube.com/watch?v=8bElojh1M-Y'),
('Hip Abduction', 'Lie on your side with legs straight. Lift your top leg up towards the ceiling.', 'Hip', 'Strength', 'https://www.youtube.com/watch?v=7M7H2m_q9zU'),
('Piriformis Stretch', 'Lie on your back, cross one leg over the other so your ankle rests on your knee. Pull your uncrossed leg towards your chest.', 'Hip', 'Stretch', 'https://www.youtube.com/watch?v=4EONMZb-R4w'),
('Hip Flexor Stretch', 'Kneel on one knee. Keep your back straight and push your hips forward gently.', 'Hip', 'Stretch', 'https://www.youtube.com/watch?v=YQldWqcZRVU'),

('Chin Tucks', 'Look straight ahead and pull your chin straight back, making a "double chin".', 'Neck', 'Stretch', 'https://www.youtube.com/watch?v=4vGErU9Z2M4'),
('Neck Rotation', 'Slowly turn your head to look over one shoulder, then the other.', 'Neck', 'Stretch', 'https://www.youtube.com/watch?v=9_HkxzvzIkg'),
('Upper Trapezius Stretch', 'Gently pull your head down towards one shoulder until you feel a stretch on the opposite side.', 'Neck', 'Stretch', 'https://www.youtube.com/watch?v=F0O5zL7U5qg'),

('Single Leg Stance', 'Stand near a support object and lift one foot off the ground. Hold for as long as possible.', 'Lower Body', 'Balance', 'https://www.youtube.com/watch?v=P21V0Qv4X4Y'),
('Tandem Stand', 'Stand near a support object and place one foot directly in front of the other, heel-to-toe. Hold your balance.', 'Lower Body', 'Balance', 'https://www.youtube.com/watch?v=gX2rQ8_dK5c');
